2072→  private placeTooltipAt(
2073→    dot: HTMLElement,
2074→    placement: 'left' | 'right',
2075→    width: number,
2076→    height: number,
2077→  ): void {
2078→    if (!this.ui.tooltip) return;
2079→    const tip = this.ui.tooltip;
2080→    const dotRect = dot.getBoundingClientRect();
2081→    const vw = window.innerWidth;
2082→    const vh = window.innerHeight;
2083→    const arrowOut = this.getCSSVarNumber(tip, '--timeline-tooltip-arrow-outside', 6);
2084→    const baseGap = this.getCSSVarNumber(tip, '--timeline-tooltip-gap-visual', 12);
2085→    const boxGap = this.getCSSVarNumber(tip, '--timeline-tooltip-gap-box', 8);
2086→    const gap = baseGap + Math.max(0, arrowOut) + Math.max(0, boxGap);
2087→    const viewportPad = 8;
2088→    let left: number;
2089→    if (placement === 'left') {
2090→      left = Math.round(dotRect.left - gap - width);
2091→      if (left < viewportPad) {
2092→        const altLeft = Math.round(dotRect.right + gap);
2093→        if (altLeft + width <= vw - viewportPad) {
2094→          placement = 'right';
2095→          left = altLeft;
2096→        } else {
2097→          const fitWidth = Math.max(120, vw - viewportPad - altLeft);
2098→          left = altLeft;
2099→          width = fitWidth;
2100→        }
2101→      }
2102→    } else {
2103→      left = Math.round(dotRect.right + gap);
2104→      if (left + width > vw - viewportPad) {
2105→        const altLeft = Math.round(dotRect.left - gap - width);
2106→        if (altLeft >= viewportPad) {
2107→          placement = 'left';
2108→          left = altLeft;
2109→        } else {
2110→          const fitWidth = Math.max(120, vw - viewportPad - left);
2111→          width = fitWidth;
2112→        }
2113→      }
2114→    }
2115→    // Set width first, let height auto-size to text
2116→    tip.style.width = `${Math.floor(width)}px`;
2117→    // If height not provided, measure after width + content set
2118→    const autoH = !height || height <= 0 ? tip.offsetHeight : height;
2119→    let top = Math.round(dotRect.top + dotRect.height / 2 - autoH / 2);
2120→    top = Math.max(viewportPad, Math.min(vh - height - viewportPad, top));
2121→    tip.style.left = `${left}px`;
2122→    tip.style.top = `${top}px`;
2123→    tip.setAttribute('data-placement', placement);
