2007→  private computePlacementInfo(dot: HTMLElement): { placement: 'left' | 'right'; width: number } {
2008→    const tip = this.ui.tooltip || document.body;
2009→    const dotRect = dot.getBoundingClientRect();
2010→    const vw = window.innerWidth;
2011→    const arrowOut = this.getCSSVarNumber(tip, '--timeline-tooltip-arrow-outside', 6);
2012→    const baseGap = this.getCSSVarNumber(tip, '--timeline-tooltip-gap-visual', 12);
2013→    const boxGap = this.getCSSVarNumber(tip, '--timeline-tooltip-gap-box', 8);
2014→    const gap = baseGap + Math.max(0, arrowOut) + Math.max(0, boxGap);
2015→    const viewportPad = 8;
2016→    const maxW = this.getCSSVarNumber(tip, '--timeline-tooltip-max', 288);
2017→    const minW = 160;
2018→    const leftAvail = Math.max(0, dotRect.left - gap - viewportPad);
2019→    const rightAvail = Math.max(0, vw - dotRect.right - gap - viewportPad);
2020→    let placement: 'left' | 'right' = rightAvail > leftAvail ? 'right' : 'left';
